const item = $input.first().json || {};

function clean(v) {
  if (v === undefined || v === null) return '';

  if (typeof v === 'object') {
    try {
      return JSON.stringify(v);
    } catch (e) {
      return '';
    }
  }

  return String(v)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function norm(v) {
  return clean(v)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function pick(...values) {
  for (const v of values) {
    const txt = clean(v);
    if (txt) return txt;
  }
  return '';
}

function parseLabels(value) {
  if (Array.isArray(value)) {
    return value.map(x => String(x).trim()).filter(Boolean);
  }

  if (typeof value === 'string') {
    const txt = value.trim();
    if (!txt) return [];

    try {
      const parsed = JSON.parse(txt);
      if (Array.isArray(parsed)) {
        return parsed.map(x => String(x).trim()).filter(Boolean);
      }
    } catch (e) {}

    return txt
      .split(',')
      .map(x => x.replace(/^\[|\]$/g, '').replace(/^"|"$/g, '').trim())
      .filter(Boolean);
  }

  return [];
}

function unique(arr) {
  return [...new Set(arr.map(x => String(x).trim()).filter(Boolean))];
}

function normalizeMessages(value) {
  if (Array.isArray(value)) {
    return value.map(clean).filter(Boolean).slice(0, 3);
  }

  const txt = clean(value);
  return txt ? [txt] : [];
}

const inputs = { ...(item.inputs || {}) };
const message = { ...(item.message || {}) };
const chatwoot = { ...(item.chatwoot || {}) };
const lead = { ...(item.lead || {}) };
const opcoesOriginais = { ...(item.opcoes || {}) };

const resumoLead = { ...(inputs.resumo_lead || {}) };
const resumoRepasse = { ...(inputs.resumo_interno_repasse || {}) };

const nomeCao = pick(resumoLead.cao_nome, 'seu cãozinho');

const pixCompleto = [
  `Perfeito, seguimos com a avaliação comportamental do ${nomeCao}.`,
  'A taxa da avaliação é R$ 100,00.',
  'Esse valor não se perde: se o cãozinho seguir no processo, ele é compensado durante a adaptação. Caso ele não passe na avaliação, o valor é devolvido via PIX.',
  'PIX/CNPJ: 27530028000197',
  'Recebedor: CANAVARRO & LEVINDO COMERCIO E SERVICOS LTDA',
  'Depois do pagamento, pode me enviar o comprovante por aqui.'
].join('\n\n');

const blocoPix = [
  'Para seguir, seguem os dados do PIX da avaliação:',
  'PIX/CNPJ: 27530028000197',
  'Recebedor: CANAVARRO & LEVINDO COMERCIO E SERVICOS LTDA',
  'Depois do pagamento, pode me enviar o comprovante por aqui.'
].join('\n\n');

const mensagensResposta = normalizeMessages(
  inputs.mensagens_resposta?.length
    ? inputs.mensagens_resposta
    : message.mensagens_resposta?.length
      ? message.mensagens_resposta
      : message.clean_answer
);

const respostaBase = clean(
  mensagensResposta.length
    ? mensagensResposta.join('\n\n')
    : message.clean_answer
);

const respostaNorm = norm(respostaBase);

const jaTemPix =
  /27530028000197/.test(respostaNorm) ||
  /canavarro/.test(respostaNorm) ||
  /cnpj/.test(respostaNorm);

const perguntaSemPix =
  /quer que eu envie|posso enviar|posso te mandar|vou enviar a chave|vou enviar o pix|envie o pix|te mando o pix|te envio o pix/.test(respostaNorm) &&
  !jaTemPix;

let cleanAnswer = '';

if (jaTemPix) {
  cleanAnswer = respostaBase;
} else if (!respostaBase || perguntaSemPix) {
  cleanAnswer = pixCompleto;
} else {
  cleanAnswer = `${respostaBase}\n\n${blocoPix}`;
}

message.clean_answer = cleanAnswer;
message.mensagens_resposta = cleanAnswer
  ? cleanAnswer.split('\n\n').map(clean).filter(Boolean).slice(0, 6)
  : [];

resumoLead.tutor_nome = pick(resumoLead.tutor_nome, lead.sender_name);
resumoLead.tutor_telefone = pick(resumoLead.tutor_telefone, lead.phone);

resumoLead.comprovante_recebido = false;
resumoLead.tipo_comprovante = 'nao_informado';
resumoLead.arquivo_comprovante_referencia = '';

resumoLead.data_hora_pre_reserva = '';
resumoLead.pre_reserva_criada = false;

resumoLead.observacoes = pick(
  resumoLead.observacoes,
  'PIX da avaliação enviado. Aguardando comprovante para conferência humana antes do alinhamento de horário.'
);

resumoRepasse.tutor_nome = pick(resumoRepasse.tutor_nome, resumoLead.tutor_nome, lead.sender_name);
resumoRepasse.tutor_telefone = pick(resumoRepasse.tutor_telefone, resumoLead.tutor_telefone, lead.phone);
resumoRepasse.cao_nome = pick(resumoRepasse.cao_nome, resumoLead.cao_nome);
resumoRepasse.cao_idade_anos = pick(resumoRepasse.cao_idade_anos, resumoLead.cao_idade_anos, resumoLead.cao_idade_texto);
resumoRepasse.cao_raca = pick(resumoRepasse.cao_raca, resumoLead.cao_raca);
resumoRepasse.cao_porte = pick(resumoRepasse.cao_porte, resumoLead.cao_porte);
resumoRepasse.cao_sexo = pick(resumoRepasse.cao_sexo, resumoLead.cao_sexo);
resumoRepasse.cao_castrado = pick(resumoRepasse.cao_castrado, resumoLead.cao_castrado);
resumoRepasse.servico_interesse = pick(resumoRepasse.servico_interesse, resumoLead.servico_interesse);
resumoRepasse.comprovante_recebido = false;
resumoRepasse.tipo_comprovante = 'nao_informado';
resumoRepasse.observacoes = pick(
  resumoRepasse.observacoes,
  resumoLead.observacoes,
  'PIX enviado. Aguardando comprovante.'
);

const statusFinal = 'AGUARDANDO_PAGAMENTO';

const intencaoAtual = clean(inputs.ultima_intencao);
const intencaoFinal = ['ACEITOU_AVALIACAO', 'RECEBEU_PIX'].includes(intencaoAtual)
  ? intencaoAtual
  : 'ACEITOU_AVALIACAO';

const eventoFinal = 'PIX_SOLICITADO';

inputs.status_lead = statusFinal;
inputs.ultima_intencao = intencaoFinal;
inputs.evento_sistema = eventoFinal;

inputs.apto_para_avaliacao = clean(inputs.apto_para_avaliacao) || 'apto';

inputs.status_pagamento = 'aguardando_comprovante';
inputs.comprovante_recebido = false;
inputs.tipo_comprovante = 'nao_informado';
inputs.arquivo_comprovante_referencia = '';

inputs.deve_repassar_humano = false;
inputs.motivo_repasse = '';
inputs.deve_enviar_guia = false;
inputs.deve_solicitar_pagamento = false;
inputs.deve_consultar_agenda = false;
inputs.deve_criar_pre_reserva = false;
inputs.deve_encerrar_conversa = false;

inputs.pre_reserva_criada = false;
inputs.data_hora_pre_reserva = '';

inputs.resumo_lead = resumoLead;
inputs.resumo_interno_repasse = resumoRepasse;
inputs.mensagens_resposta = message.mensagens_resposta;

const labelsAtuais = unique([
  ...parseLabels(chatwoot.labels),
  ...parseLabels(opcoesOriginais.labels_new)
]);

let labelsFinal = labelsAtuais.filter(label => ![
  '99-lead-desqualificado',
  '99-macho-nao-castrado',
  '99-raca-nao-aceita',
  '35-avaliacao-comprovante-recebido',
  '40-pre-reserva-avaliacao',
].includes(label));

labelsFinal.push('01-em-atendimento');
// labelsFinal.push('01-bruna-atendimento');
labelsFinal.push('10-lead-qualificado');
labelsFinal.push('31-aguardando-pix-avaliacao');

const servico = clean(resumoLead.servico_interesse).toLowerCase();

if (servico === 'hotel') {
  labelsFinal.push('15-interesse-hotel');
}

if (servico === 'creche') {
  labelsFinal.push('15-interesse-creche');
}

labelsFinal = unique(labelsFinal);

const opcoes = {
  ...opcoesOriginais,

  envia_chatwoot: true,
  atualizar_contact_summary: true,
  gravar_memoria: true,
  gravar_historico: true,

  atualiza_labels: true,
  labels_new: labelsFinal,

  adicionar_nota_privada: false,
  nota_privada_texto: '',

  pula_verificao_ultima_mensagem: false,
  tipo_registro_historico: 'pagamento',
  origem_registro_historico: 'n8n'
};

return [
  {
    json: {
      message,
      lead,
      chatwoot,
      inputs,
      opcoes
    }
  }
];

