const current = items[0]?.json || {};

const phone =
  current.lead?.phone ||
  current.inputs?.resumo_lead?.tutor_telefone ||
  '';

const accountId = current.chatwoot?.account_id ?? null;
const contactId = current.chatwoot?.contact_id ?? null;
const conversationId = current.chatwoot?.conversation_id ?? null;
const messageId = current.chatwoot?.message_id ?? null;
const chatHistoryUuid = current.chatwoot?.chat_history_uuid ?? null;

const statusLeadNovo = current.inputs?.status_lead || 'TRANSFERIDO_FLAVIA';
const ultimaIntencaoNova = current.inputs?.ultima_intencao || 'PEDIU_HUMANO';
const eventoSistemaNovo = current.inputs?.evento_sistema || 'REPASSE_FLAVIA';
const resumoLeadJson = current.inputs?.resumo_lead || {};

const mensagensResposta = Array.isArray(current.inputs?.mensagens_resposta)
  ? current.inputs.mensagens_resposta
  : [];

const motivoRepasse = String(current.inputs?.motivo_repasse || '').toLowerCase();

let fallback = 'Perfeito. Vou encaminhar seu atendimento para a Flávia seguir com você.';

if (['horario', 'horário', 'agenda', 'data', 'dia'].some(x => motivoRepasse.includes(x))) {
  fallback = 'Perfeito. Vou encaminhar seu atendimento para a Flávia te ajudar com outras opções.';
}

const cleanAnswer = mensagensResposta.join('\n\n') || current.message?.clean_answer || fallback;

return [
  {
    json: {
      ...current,
      message: {
        ...(current.message || {}),
        clean_answer: cleanAnswer
      },
      resposta: {
        phone,
        chat_history_uuid: chatHistoryUuid,
