/*
  ==================================================
  PREPARA CHATWOOT
  ==================================================

  Payload final:
  message
  lead
  chatwoot
  inputs
  opcoes

  Não usa:
  resposta
  memory
  controle
*/

const item = $input.first().json || {};

function isObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function ensureObject(value) {
  return isObject(value) ? value : {};
}

function cleanText(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return '';
    }
  }

  return String(value)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function normalizeMessages(value) {
  if (Array.isArray(value)) {
    return value
      .map(cleanText)
      .filter(Boolean)
      .slice(0, 3);
  }

  const txt = cleanText(value);
  return txt ? [txt] : [];
}

function parseLabels(value) {
  if (Array.isArray(value)) {
    return value.map(x => String(x).trim()).filter(Boolean);
  }

  if (typeof value === 'string') {
    const txt = value.trim();
    if (!txt) return [];

    try {
      const parsed = JSON.parse(txt);
      if (Array.isArray(parsed)) {
        return parsed.map(x => String(x).trim()).filter(Boolean);
      }
    } catch (e) {}

    return txt
      .split(',')
      .map(x => x.replace(/^\[|\]$/g, '').replace(/^"|"$/g, '').trim())
      .filter(Boolean);
  }

  return [];
}

function unique(values) {
  return [...new Set(values.map(x => String(x).trim()).filter(Boolean))];
}

const inputs = ensureObject(item.inputs);
const message = ensureObject(item.message);
const chatwoot = ensureObject(item.chatwoot);
const lead = ensureObject(item.lead);
const opcoesOriginais = ensureObject(item.opcoes);

inputs.resumo_lead = ensureObject(inputs.resumo_lead);
inputs.resumo_interno_repasse = ensureObject(inputs.resumo_interno_repasse);

/*
  ==================================================
  1. Normaliza resposta da Bruna
  ==================================================
*/

const mensagensResposta = normalizeMessages(
  Array.isArray(inputs.mensagens_resposta) && inputs.mensagens_resposta.length
    ? inputs.mensagens_resposta
    : message.mensagens_resposta
);

const cleanAnswer = cleanText(
  mensagensResposta.length
    ? mensagensResposta.join('\n\n')
    : message.clean_answer
);

inputs.mensagens_resposta = cleanAnswer
  ? cleanAnswer.split('\n\n').map(cleanText).filter(Boolean).slice(0, 3)
  : [];

message.clean_answer = cleanAnswer;
message.mensagens_resposta = inputs.mensagens_resposta;

/*
  ==================================================
  2. Travas finais do fluxo novo
  ==================================================
*/

inputs.deve_consultar_agenda = false;
inputs.deve_criar_pre_reserva = false;
inputs.pre_reserva_criada = false;
inputs.data_hora_pre_reserva = '';

inputs.resumo_lead.data_hora_pre_reserva = '';
inputs.resumo_lead.pre_reserva_criada = false;

/*
  Não zerar data_hora_avaliacao aqui.
  Pode ter vindo de humano, histórico ou outro branch.
*/

/*
  ==================================================
  3. Labels
  ==================================================
*/

const labelsAtuais = unique([
  ...parseLabels(chatwoot.labels),
  ...parseLabels(item.labels),
  ...parseLabels(opcoesOriginais.labels_new)
]);

const humanoAssumiu =
  labelsAtuais.includes('01-humano-assumiu') ||
  labelsAtuais.includes('humano-assumiu');

const servico = cleanText(inputs.resumo_lead.servico_interesse).toLowerCase();

let labels = [...labelsAtuais];

labels.push('01-em-atendimento');

/*
  Decisão de negócio:
  não adicionar 01-bruna-atendimento aqui
  não remover 01-humano-assumiu aqui
*/

if (servico === 'hotel') {
  labels.push('15-interesse-hotel');
}

if (servico === 'creche') {
  labels.push('15-interesse-creche');
}

labels = unique(labels);

/*
  ==================================================
  4. should reply
  ==================================================
*/

const shouldReply =
  item.should_reply === false
    ? false
    : humanoAssumiu
      ? false
      : cleanAnswer.length > 0;

/*
  ==================================================
  5. Opções para subworkflow
  ==================================================
*/

const opcoes = {
  ...opcoesOriginais,

  envia_chatwoot: shouldReply,
  atualizar_contact_summary: true,
  gravar_memoria: true,
  gravar_historico: shouldReply,

  atualiza_labels: true,
  labels_new: labels,

  pula_verificao_ultima_mensagem: false,
  tipo_registro_historico: 'mensagem_bruna',
  origem_registro_historico: 'n8n'
};

return [
  {
    json: {
      message,
      lead,
      chatwoot,
      inputs,
      opcoes
    }
  }
];

const item = $input.first().json || {};

function clean(v) {
  if (v === undefined || v === null) return '';

  if (typeof v === 'object') {
    try {
      return JSON.stringify(v);
    } catch (e) {
      return '';
    }
  }

  return String(v)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function pick(...values) {
  for (const v of values) {
    const txt = clean(v);
    if (txt) return txt;
  }

  return '';
}

function parseLabels(value) {
  if (Array.isArray(value)) {
    return value.map(x => String(x).trim()).filter(Boolean);
  }

  if (typeof value === 'string') {
