  );

  if (tipoAtual && tipoAtual !== 'nao_informado') {
    return tipoAtual;
  }

  const modality = clean(message.message_modality).toLowerCase();

  if (modality.includes('image')) return 'imagem';
  if (modality.includes('document')) return 'documento';
  if (message.has_attachment === true) return 'anexo';

  return 'nao_informado';
}

