const item = $input.first().json || {};

function clean(v) {
  if (v === undefined || v === null) return '';

  if (typeof v === 'object') {
    try {
      return JSON.stringify(v);
    } catch (e) {
      return '';
    }
  }

  return String(v)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function pick(...values) {
  for (const v of values) {
    const txt = clean(v);
    if (txt) return txt;
  }

  return '';
}

function parseLabels(value) {
  if (Array.isArray(value)) {
    return value.map(x => String(x).trim()).filter(Boolean);
  }

  if (typeof value === 'string') {
    const txt = value.trim();

    if (!txt) return [];

    try {
      const parsed = JSON.parse(txt);
      if (Array.isArray(parsed)) {
        return parsed.map(x => String(x).trim()).filter(Boolean);
      }
    } catch (e) {}

    return txt
      .split(',')
      .map(x => x.replace(/^\[|\]$/g, '').replace(/^"|"$/g, '').trim())
      .filter(Boolean);
  }

  return [];
}

function unique(arr) {
  return [...new Set(arr.map(x => String(x).trim()).filter(Boolean))];
}

function normalizeMessages(value) {
  if (Array.isArray(value)) {
    return value.map(clean).filter(Boolean).slice(0, 3);
  }

  const txt = clean(value);
  return txt ? [txt] : [];
}

const inputs = { ...(item.inputs || {}) };
const message = { ...(item.message || {}) };
const chatwoot = { ...(item.chatwoot || {}) };
const lead = { ...(item.lead || {}) };
const opcoesOriginais = { ...(item.opcoes || {}) };

const resumoLead = { ...(inputs.resumo_lead || {}) };
const resumoRepasse = { ...(inputs.resumo_interno_repasse || {}) };

const inboxId = Number(chatwoot.inbox_id || 0);

const guia = (() => {
  if (inboxId === 13) {
    return {
      tipo: 'auauzin',
      arquivo: 'guia_auauzin.pdf',
      descricao: 'Guia AuAuzin'
    };
  }

  return {
    tipo: 'auau',
    arquivo: 'guia_auau.pdf',
    descricao: 'Guia AuAu'
  };
})();

const statusAtual = clean(inputs.status_lead);
const statusFinal = statusAtual && statusAtual !== 'NOVO_LEAD'
  ? statusAtual
  : 'QUALIFICANDO';

const ultimaIntencaoFinal = clean(inputs.ultima_intencao) || 'INTERESSE_CRECHE';
