  inputs.mensagens_resposta?.length
    ? inputs.mensagens_resposta
    : message.mensagens_resposta?.length
      ? message.mensagens_resposta
      : message.clean_answer
);

const cleanAnswer = clean(
  mensagensResposta.length
    ? mensagensResposta.join('\n\n')
    : message.clean_answer || fallbackMensagem
);

message.clean_answer = cleanAnswer;
message.mensagens_resposta = cleanAnswer
  ? cleanAnswer.split('\n\n').map(clean).filter(Boolean).slice(0, 3)
  : [fallbackMensagem];

resumoLead.tutor_nome = pick(resumoLead.tutor_nome, lead.sender_name);
resumoLead.tutor_telefone = pick(resumoLead.tutor_telefone, lead.phone);
resumoLead.guia_enviado = true;

resumoLead.data_hora_pre_reserva = '';
resumoLead.pre_reserva_criada = false;

resumoLead.observacoes = pick(
  resumoLead.observacoes,
  `${guia.descricao} enviado ao lead. Atendimento segue ativo.`
);

resumoRepasse.tutor_nome = pick(resumoRepasse.tutor_nome, resumoLead.tutor_nome, lead.sender_name);
resumoRepasse.tutor_telefone = pick(resumoRepasse.tutor_telefone, resumoLead.tutor_telefone, lead.phone);
resumoRepasse.cao_nome = pick(resumoRepasse.cao_nome, resumoLead.cao_nome);
resumoRepasse.cao_idade_anos = pick(resumoRepasse.cao_idade_anos, resumoLead.cao_idade_anos, resumoLead.cao_idade_texto);
resumoRepasse.cao_raca = pick(resumoRepasse.cao_raca, resumoLead.cao_raca);
resumoRepasse.cao_porte = pick(resumoRepasse.cao_porte, resumoLead.cao_porte);
resumoRepasse.cao_sexo = pick(resumoRepasse.cao_sexo, resumoLead.cao_sexo);
resumoRepasse.cao_castrado = pick(resumoRepasse.cao_castrado, resumoLead.cao_castrado);
resumoRepasse.servico_interesse = pick(resumoRepasse.servico_interesse, resumoLead.servico_interesse);
resumoRepasse.observacoes = pick(
  resumoRepasse.observacoes,
  resumoLead.observacoes,
  `${guia.descricao} enviado.`
);

inputs.status_lead = statusFinal;
inputs.ultima_intencao = ultimaIntencaoFinal;
inputs.evento_sistema = eventoFinal;

inputs.guia_enviado = true;

inputs.deve_enviar_guia = false;
inputs.deve_repassar_humano = false;
inputs.motivo_repasse = '';
inputs.deve_solicitar_pagamento = false;
inputs.deve_consultar_agenda = false;
inputs.deve_criar_pre_reserva = false;
inputs.deve_encerrar_conversa = false;

inputs.pre_reserva_criada = false;
inputs.data_hora_pre_reserva = '';

inputs.resumo_lead = resumoLead;
inputs.resumo_interno_repasse = resumoRepasse;
inputs.mensagens_resposta = message.mensagens_resposta;

const labelsAtuais = unique([
  ...parseLabels(chatwoot.labels),
  ...parseLabels(opcoesOriginais.labels_new)
]);

let labelsFinal = labelsAtuais.filter(label => ![
  '99-lead-desqualificado',
  '99-macho-nao-castrado',
  '99-raca-nao-aceita',
  '99-sem-resposta',
  '99-lead-encerrado'
].includes(label));

labelsFinal.push('01-em-atendimento');
// labelsFinal.push('01-bruna-atendimento');

const servico = clean(resumoLead.servico_interesse).toLowerCase();

if (servico === 'hotel') {
  labelsFinal.push('15-interesse-hotel');
}

if (servico === 'creche') {
  labelsFinal.push('15-interesse-creche');
}

labelsFinal = unique(labelsFinal);

const opcoes = {
  ...opcoesOriginais,

  envia_chatwoot: true,
  atualizar_contact_summary: true,
  gravar_memoria: true,
  gravar_historico: true,

  atualiza_labels: true,
  labels_new: labelsFinal,

  adicionar_nota_privada: false,
  nota_privada_texto: '',

  enviar_guia: true,
  guia_tipo: guia.tipo,
  link_guia: guia.arquivo,
  guia_descricao: guia.descricao,

  pula_verificao_ultima_mensagem: false,
  tipo_registro_historico: 'evento_sistema',
  origem_registro_historico: 'n8n'
};

return [
  {
    json: {
      message,
      lead,
      chatwoot,
      inputs,
      opcoes
    }
  }
];

const input = $json || {};

const mensagensArray = Array.isArray(input.mensagens_resposta)
  ? input.mensagens_resposta.filter(Boolean)
  : [];

const mensagens = mensagensArray.join('\n').toLowerCase();
const ultimaMensagem = String(mensagensArray[mensagensArray.length - 1] || '').trim();

const resumo = input.resumo_lead || {};

const start = $json || {};
const message = start.message || {};
const textoLead = String(message.content || '').toLowerCase();

const erros = [];

// ======================================================
// Helpers
// ======================================================

const has = (regex, text = textoLead) => regex.test(text);
const respostaTem = (regex) => regex.test(mensagens);

const conversaContinua =
  input.deve_encerrar_conversa !== true &&
  input.deve_repassar_humano !== true &&
  input.status_lead !== 'ENCERRADO_NAO_PERFIL' &&
  input.status_lead !== 'ENCERRADO_SEM_RESPOSTA' &&
  input.status_lead !== 'ENCERRADO' &&
  input.status_lead !== 'TRANSFERIDO_FLAVIA';

const ultimaTemPerguntaOuConvite =
  /[?？]\s*$/.test(ultimaMensagem) ||
  /(me diga|me fala|me conta|pode me mandar|pode responder|me confirma|envia por aqui|mande por aqui|chama por aqui|me avisa|posso te explicar|quer que eu)/i.test(ultimaMensagem);

// ======================================================
// Intenções do lead
// ======================================================

const pediuPreco = has(/valor|preço|preco|mensal|mensalidade|diária|diaria|pacote|plano|quanto|custa|custaria|tabela/);

const pediuMensal = has(/mensal|mensalidade|plano mensal|planos mensais|pacote mensal/);

const pediuLocalizacaoGenerica = has(/onde fica|onde é|onde e|endereço|endereco|localização|localizacao|qual unidade|unidades|fica onde|bairro/);

const pediuAmaralinaEspecifico = has(/amaralina/);
const pediuPatamaresEspecifico = has(/patamares|auauzin/);

const pediuLocalizacao =
  pediuLocalizacaoGenerica ||
  pediuAmaralinaEspecifico ||
  pediuPatamaresEspecifico;

const pediuVisitaOuMaterial = has(/visita|visitar|conhecer|estrutura|fotos|foto|material|guia|site|instagram|canal/);

// ======================================================
// Sinais de resposta da Bruna
// ======================================================

const respondeuPreco =
  respostaTem(/r\$|\breais\b|valor|preço|preco|diária|diaria|mensal|plano|pacote|avulsa|avulso/);

const respondeuMensal =
  respostaTem(/mensal|mensalidade|plano|planos|frequência|frequencia|vez(?:es)? por semana|1x|2x|3x|4x|5x/);

const citouAmaralina = respostaTem(/amaralina|manoel dias/);
const citouPatamares = respostaTem(/patamares|auauzin|pinto de aguiar/);

const respondeuLocalizacaoGenerica = citouAmaralina && citouPatamares;
const respondeuAmaralinaEspecifico = citouAmaralina;
const respondeuPatamaresEspecifico = citouPatamares;

const respondeuVisitaOuMaterial =
  respostaTem(/conhecer|visita|visitar|estrutura|câmera|camera|fotos|foto|material|guia|site|instagram|redes sociais/);

const falouPagamento =
  respostaTem(/pix|pagamento|comprovante|pagar|taxa/);

// ======================================================
// Validações
// ======================================================

// 1. Preço
if (pediuPreco && !respondeuPreco) {
  erros.push('Lead pediu preço, mas a Bruna não respondeu valor, plano, diária, pacote ou referência objetiva de preço.');
}

// 2. Mensalidade
if (pediuMensal && !respondeuMensal) {
  erros.push('Lead pediu mensalidade/plano, mas a Bruna não respondeu sobre planos mensais ou frequência semanal.');
}

// 3. Localização
if (pediuLocalizacaoGenerica && !respondeuLocalizacaoGenerica) {
  erros.push('Lead pediu localização genérica, mas a Bruna não citou as duas unidades.');
}

if (pediuAmaralinaEspecifico && !pediuLocalizacaoGenerica && !respondeuAmaralinaEspecifico) {
  erros.push('Lead perguntou sobre Amaralina, mas a Bruna não respondeu Amaralina.');
}

if (pediuPatamaresEspecifico && !pediuLocalizacaoGenerica && !respondeuPatamaresEspecifico) {
  erros.push('Lead perguntou sobre Patamares/AuAuzin, mas a Bruna não respondeu Patamares/AuAuzin.');
}

// 4. Visita, fotos, material
if (pediuVisitaOuMaterial && !respondeuVisitaOuMaterial) {
  erros.push('Lead pediu visita, fotos, material ou canal para conhecer melhor, mas a Bruna não respondeu essa dúvida.');
}

if (pediuVisitaOuMaterial && falouPagamento && !respondeuVisitaOuMaterial) {
  erros.push('Lead pediu visita/material, mas a Bruna voltou para pagamento sem responder a dúvida.');
}

// 5. Conversa continua sem pergunta ou convite claro
if (conversaContinua && !ultimaTemPerguntaOuConvite) {
  erros.push('Conversa continua, mas a última mensagem não termina com pergunta útil nem convite claro para próximo passo.');
}

// 6. Castração reconhecida no texto, mas não salva no campo estruturado
const reconheceuCastracaoNoTexto =
  respostaTem(/confirm(?:ar|ado|ada|ei|ou)? .*castra|castração confirmada|castrado|castrada|ele é castrado|ela é castrada/);

if (
  resumo.cao_castrado === 'nao_informado' &&
  reconheceuCastracaoNoTexto
) {
  erros.push('A Bruna reconheceu castração no texto, mas resumo_lead.cao_castrado ficou nao_informado.');
}

// 7. Pix cedo demais
const leadAceitouAvaliacao =
  /quero seguir|pode mandar.*pix|manda.*pix|vou pagar|quero avaliação|quero avaliacao|pode agendar|vamos fazer/.test(textoLead);

if (
  falouPagamento &&
  input.deve_solicitar_pagamento === true &&
  !leadAceitouAvaliacao &&
  pediuPreco
) {
  erros.push('Bruna sinalizou pagamento/PIX em turno de preço sem aceite claro de avaliação.');
}

// ======================================================
// Saída
// ======================================================

return [
  {
    json: {
      ...input,
      guard_pos_bruna: {
        aprovado: erros.length === 0,
        erros,
        precisa_reprocessar: erros.length > 0,
        sinais_detectados: {
          pediuPreco,
          pediuMensal,
          pediuLocalizacao,
          pediuLocalizacaoGenerica,
          pediuAmaralinaEspecifico,
          pediuPatamaresEspecifico,
          pediuVisitaOuMaterial,
          respondeuPreco,
          respondeuMensal,
          respondeuLocalizacaoGenerica,
          respondeuVisitaOuMaterial,
          conversaContinua
        }
      }
    }
  }
];

