/*
  ==================================================
  PREPARA CHATWOOT
  ==================================================

  Payload final:
  message
  lead
  chatwoot
  inputs
  opcoes

  Não usa:
  resposta
  memory
  controle
*/

const item = $input.first().json || {};

function isObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function ensureObject(value) {
  return isObject(value) ? value : {};
}

function cleanText(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'object') {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return '';
    }
  }

  return String(value)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function normalizeMessages(value) {
  if (Array.isArray(value)) {
    return value
      .map(cleanText)
      .filter(Boolean)
      .slice(0, 3);
  }

  const txt = cleanText(value);
  return txt ? [txt] : [];
}

function parseLabels(value) {
  if (Array.isArray(value)) {
    return value.map(x => String(x).trim()).filter(Boolean);
  }

  if (typeof value === 'string') {
    const txt = value.trim();
    if (!txt) return [];

    try {
      const parsed = JSON.parse(txt);
      if (Array.isArray(parsed)) {
        return parsed.map(x => String(x).trim()).filter(Boolean);
      }
    } catch (e) {}

    return txt
      .split(',')
      .map(x => x.replace(/^\[|\]$/g, '').replace(/^"|"$/g, '').trim())
      .filter(Boolean);
  }

  return [];
}

function unique(values) {
  return [...new Set(values.map(x => String(x).trim()).filter(Boolean))];
}

const inputs = ensureObject(item.inputs);
const message = ensureObject(item.message);
const chatwoot = ensureObject(item.chatwoot);
const lead = ensureObject(item.lead);
const opcoesOriginais = ensureObject(item.opcoes);

inputs.resumo_lead = ensureObject(inputs.resumo_lead);
inputs.resumo_interno_repasse = ensureObject(inputs.resumo_interno_repasse);

/*
  ==================================================
  1. Normaliza resposta da Bruna
  ==================================================
*/

const mensagensResposta = normalizeMessages(
  Array.isArray(inputs.mensagens_resposta) && inputs.mensagens_resposta.length
    ? inputs.mensagens_resposta
    : message.mensagens_resposta
);

const cleanAnswer = cleanText(
  mensagensResposta.length
    ? mensagensResposta.join('\n\n')
    : message.clean_answer
);

inputs.mensagens_resposta = cleanAnswer
  ? cleanAnswer.split('\n\n').map(cleanText).filter(Boolean).slice(0, 3)
  : [];

message.clean_answer = cleanAnswer;
message.mensagens_resposta = inputs.mensagens_resposta;

/*
  ==================================================
  2. Travas finais do fluxo novo
  ==================================================
*/

inputs.deve_consultar_agenda = false;
inputs.deve_criar_pre_reserva = false;
inputs.pre_reserva_criada = false;
inputs.data_hora_pre_reserva = '';

inputs.resumo_lead.data_hora_pre_reserva = '';
inputs.resumo_lead.pre_reserva_criada = false;

/*
  Não zerar data_hora_avaliacao aqui.
  Pode ter vindo de humano, histórico ou outro branch.
*/

/*
  ==================================================
  3. Labels
  ==================================================
*/

const labelsAtuais = unique([
  ...parseLabels(chatwoot.labels),
  ...parseLabels(item.labels),
  ...parseLabels(opcoesOriginais.labels_new)
]);

const humanoAssumiu =
  labelsAtuais.includes('01-humano-assumiu') ||
  labelsAtuais.includes('humano-assumiu');

const servico = cleanText(inputs.resumo_lead.servico_interesse).toLowerCase();

let labels = [...labelsAtuais];

labels.push('01-em-atendimento');

/*
  Decisão de negócio:
  não adicionar 01-bruna-atendimento aqui
  não remover 01-humano-assumiu aqui
*/

if (servico === 'hotel') {
  labels.push('15-interesse-hotel');
}

if (servico === 'creche') {
  labels.push('15-interesse-creche');
}

labels = unique(labels);

/*
  ==================================================
  4. should reply
  ==================================================
*/

const shouldReply =
  item.should_reply === false
    ? false
    : humanoAssumiu
      ? false
      : cleanAnswer.length > 0;

/*
  ==================================================
  5. Opções para subworkflow
  ==================================================
*/

const opcoes = {
  ...opcoesOriginais,

  envia_chatwoot: shouldReply,
  atualizar_contact_summary: true,
  gravar_memoria: true,
  gravar_historico: shouldReply,

  atualiza_labels: true,
  labels_new: labels,

  pula_verificao_ultima_mensagem: false,
  tipo_registro_historico: 'mensagem_bruna',
  origem_registro_historico: 'n8n'
};

return [
  {
    json: {
      message,
      lead,
      chatwoot,
      inputs,
      opcoes
    }
  }
];

const item = $input.first().json || {};

function clean(v) {
  if (v === undefined || v === null) return '';

  if (typeof v === 'object') {
    try {
      return JSON.stringify(v);
    } catch (e) {
      return '';
    }
  }

  return String(v)
    .replace(/\[object Object\]/gi, '')
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
    .replace(/\uFFFD/g, ' ')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function pick(...values) {
  for (const v of values) {
    const txt = clean(v);
    if (txt) return txt;
  }

  return '';
}

function parseLabels(value) {
  if (Array.isArray(value)) {
    return value.map(x => String(x).trim()).filter(Boolean);
  }

  if (typeof value === 'string') {
    const txt = value.trim();

    if (!txt) return [];

    try {
      const parsed = JSON.parse(txt);
      if (Array.isArray(parsed)) {
        return parsed.map(x => String(x).trim()).filter(Boolean);
      }
    } catch (e) {}

    return txt
      .split(',')
      .map(x => x.replace(/^\[|\]$/g, '').replace(/^"|"$/g, '').trim())
      .filter(Boolean);
  }

  return [];
}

function unique(arr) {
  return [...new Set(arr.map(x => String(x).trim()).filter(Boolean))];
}

function normalizeMessages(value) {
  if (Array.isArray(value)) {
    return value.map(clean).filter(Boolean).slice(0, 3);
  }

  const txt = clean(value);
  return txt ? [txt] : [];
}

const inputs = { ...(item.inputs || {}) };
const message = { ...(item.message || {}) };
const chatwoot = { ...(item.chatwoot || {}) };
const lead = { ...(item.lead || {}) };
const opcoesOriginais = { ...(item.opcoes || {}) };

const resumoLead = { ...(inputs.resumo_lead || {}) };
const resumoRepasse = { ...(inputs.resumo_interno_repasse || {}) };

const statusAtual = clean(inputs.status_lead);
const ultimaIntencao = clean(inputs.ultima_intencao);

const statusEncerradoValido = [
  'ENCERRADO_NAO_PERFIL',
  'ENCERRADO_SEM_RESPOSTA',
  'ENCERRADO'
];

const statusFinal = statusEncerradoValido.includes(statusAtual)
  ? statusAtual
  : ['MACHO_NAO_CASTRADO', 'RACA_POTENCIAL_DANO'].includes(ultimaIntencao)
    ? 'ENCERRADO_NAO_PERFIL'
    : 'ENCERRADO';

const eventoFinal = 'CONVERSA_ENCERRADA';

const mensagensResposta = normalizeMessages(
  inputs.mensagens_resposta?.length
    ? inputs.mensagens_resposta
    : message.mensagens_resposta?.length
      ? message.mensagens_resposta
      : message.clean_answer
);

const cleanAnswer = clean(
  mensagensResposta.length
    ? mensagensResposta.join('\n\n')
    : message.clean_answer
);

message.clean_answer = cleanAnswer;
message.mensagens_resposta = cleanAnswer
  ? cleanAnswer.split('\n\n').map(clean).filter(Boolean).slice(0, 3)
  : [];

resumoLead.tutor_nome = pick(resumoLead.tutor_nome, lead.sender_name);
resumoLead.tutor_telefone = pick(resumoLead.tutor_telefone, lead.phone);
resumoLead.responsavel_humano = '';

resumoLead.data_hora_pre_reserva = '';
resumoLead.pre_reserva_criada = false;

resumoRepasse.repassar_para = '';
resumoRepasse.motivo = '';
resumoRepasse.tutor_nome = pick(resumoRepasse.tutor_nome, resumoLead.tutor_nome, lead.sender_name);
resumoRepasse.tutor_telefone = pick(resumoRepasse.tutor_telefone, resumoLead.tutor_telefone, lead.phone);
resumoRepasse.cao_nome = pick(resumoRepasse.cao_nome, resumoLead.cao_nome);
resumoRepasse.cao_idade_anos = pick(resumoRepasse.cao_idade_anos, resumoLead.cao_idade_anos, resumoLead.cao_idade_texto);
resumoRepasse.cao_raca = pick(resumoRepasse.cao_raca, resumoLead.cao_raca);
resumoRepasse.cao_porte = pick(resumoRepasse.cao_porte, resumoLead.cao_porte);
resumoRepasse.cao_sexo = pick(resumoRepasse.cao_sexo, resumoLead.cao_sexo);
resumoRepasse.cao_castrado = pick(resumoRepasse.cao_castrado, resumoLead.cao_castrado);
resumoRepasse.servico_interesse = pick(resumoRepasse.servico_interesse, resumoLead.servico_interesse);
resumoRepasse.observacoes = pick(resumoRepasse.observacoes, resumoLead.observacoes);

inputs.status_lead = statusFinal;
inputs.evento_sistema = eventoFinal;
inputs.ultima_intencao = ultimaIntencao;

inputs.deve_repassar_humano = false;
inputs.motivo_repasse = '';
inputs.deve_enviar_guia = false;
inputs.deve_solicitar_pagamento = false;
inputs.deve_consultar_agenda = false;
inputs.deve_criar_pre_reserva = false;
inputs.deve_encerrar_conversa = true;

inputs.pre_reserva_criada = false;
inputs.data_hora_pre_reserva = '';

inputs.resumo_lead = resumoLead;
inputs.resumo_interno_repasse = resumoRepasse;
inputs.mensagens_resposta = message.mensagens_resposta;

const labelsAtuais = unique([
  ...parseLabels(chatwoot.labels),
  ...parseLabels(opcoesOriginais.labels_new)
]);

let labelsFinal = labelsAtuais.filter(label => ![
  '01-bruna-atendimento',
  '10-lead-qualificado',
  '31-aguardando-pix-avaliacao',
  '40-pre-reserva-avaliacao'
].includes(label));

if (statusFinal === 'ENCERRADO_NAO_PERFIL') {
  labelsFinal.push('99-lead-desqualificado');
} else if (statusFinal === 'ENCERRADO_SEM_RESPOSTA') {
  labelsFinal.push('99-sem-resposta');
} else {
  labelsFinal.push('99-lead-encerrado');
}

if (ultimaIntencao === 'MACHO_NAO_CASTRADO') {
  labelsFinal.push('99-macho-nao-castrado');
}

if (ultimaIntencao === 'RACA_POTENCIAL_DANO') {
  labelsFinal.push('99-raca-nao-aceita');
}

labelsFinal = unique(labelsFinal);

const motivo =
  ultimaIntencao === 'MACHO_NAO_CASTRADO'
    ? 'Macho não castrado a partir de 8 meses'
    : ultimaIntencao === 'RACA_POTENCIAL_DANO'
      ? 'Raça com grande potencial de dano'
      : statusFinal === 'ENCERRADO_SEM_RESPOSTA'
        ? 'Encerrado sem resposta'
        : statusFinal === 'ENCERRADO_NAO_PERFIL'
          ? 'Não perfil objetivo'
          : 'Encerramento operacional';

const notaPrivada = [
  '[ENCERRAMENTO BRUNA]',
  '',
  `Motivo: ${motivo}`,
  `Status final: ${statusFinal}`,
  `Última intenção: ${ultimaIntencao || 'não informada'}`,
  '',
  `Tutor: ${pick(resumoRepasse.tutor_nome, resumoLead.tutor_nome, lead.sender_name)}`,
  `Telefone: ${pick(resumoRepasse.tutor_telefone, resumoLead.tutor_telefone, lead.phone)}`,
  `Cão: ${pick(resumoRepasse.cao_nome, resumoLead.cao_nome)}`,
  `Idade: ${pick(resumoRepasse.cao_idade_anos, resumoLead.cao_idade_anos, resumoLead.cao_idade_texto)}`,
  `Raça: ${pick(resumoRepasse.cao_raca, resumoLead.cao_raca)}`,
  `Porte: ${pick(resumoRepasse.cao_porte, resumoLead.cao_porte)}`,
  `Sexo: ${pick(resumoRepasse.cao_sexo, resumoLead.cao_sexo)}`,
  `Castrado: ${pick(resumoRepasse.cao_castrado, resumoLead.cao_castrado)}`,
  `Serviço: ${pick(resumoRepasse.servico_interesse, resumoLead.servico_interesse)}`,
  '',
  `Observações: ${pick(resumoRepasse.observacoes, resumoLead.observacoes)}`
].join('\n');

const opcoes = {
  ...opcoesOriginais,

  envia_chatwoot: cleanAnswer.length > 0,
  atualizar_contact_summary: true,
  gravar_memoria: true,
  gravar_historico: true,

  atualiza_labels: true,
  labels_new: labelsFinal,

  adicionar_nota_privada: true,
